t.script:
                document.addEventListener('DOMContentLoaded', function () {
                    // 1. Initial Counters from Server
                    let bankCounter = ;
                    let familyCounter = ;
                    let educationCounter = ;
                    let experienceCounter = ;

                    const prefix = 'ahadu_onboarding_';
                    const form = document.getElementById('ahadu_onboarding_form');

                    // Standardize Bootstrap Dropdown behaviour for custom checklist
                    const languageDropdownEl = document.getElementById('languageDropdown');
                    if (languageDropdownEl && window.bootstrap) {
                        new bootstrap.Dropdown(languageDropdownEl);
                    }

                    // Dynamic Multi-Select Dropdown Selection Logic
                    const checkboxes = document.querySelectorAll('.language-checkbox');
                    const hiddenSelect = document.getElementById('language_ids');
                    const selectedLabel = document.getElementById('selected_languages_label');
                    const langSearch = document.getElementById('langSearch');
                    const selectAllCb = document.getElementById('selectAllLanguages');

                    function updateSelectedLanguages() {
                        const selectedText = [];
                        const selectedIds = [];
                        let checkedCount = 0;

                        checkboxes.forEach(cb => {
                            if (cb.checked) {
                                const label = document.querySelector('label[for="' + cb.id + '"]');
                                if (label) selectedText.push(label.textContent.trim());
                                selectedIds.push(cb.value);
                                checkedCount++;
                            }
                        });

                        // Sync selections to hidden standard many2many select
                        if (hiddenSelect) {
                            Array.from(hiddenSelect.options).forEach(opt => {
                                opt.selected = selectedIds.some(id => String(id).trim() === String(opt.value).trim());
                            });
                        }

                        // Update displayed label text
                        if (selectedText.length === 0) {
                            selectedLabel.textContent = "Select languages...";
                        } else if (selectedText.length <= 3) {
                            selectedLabel.textContent = selectedText.join(', ');
                        } else {
                            selectedLabel.textContent = selectedText.length + " languages selected";
                        }

                        // Sync Select/Unselect All checkbox state
                        if (selectAllCb) {
                            selectAllCb.checked = checkboxes.length > 0 && checkedCount === checkboxes.length;
                        }

                        // Save selections to LocalStorage draft
                        localStorage.setItem('ahadu_onboarding_language_ids', selectedIds.join(','));
                    }

                    // Bind change event to custom checklist checkboxes
                    checkboxes.forEach(cb => {
                        cb.addEventListener('change', updateSelectedLanguages);
                    });

                    // Select/Unselect All click handler
                    if (selectAllCb) {
                        selectAllCb.addEventListener('change', function() {
                            const checkedState = this.checked;
                            checkboxes.forEach(cb => {
                                const listItem = cb.closest('li.dropdown-item-text');
                                const isVisible = listItem ? !listItem.classList.contains('d-none') : true;
                                if (isVisible) {
                                    cb.checked = checkedState;
                                }
                            });
                            updateSelectedLanguages();
                        });
                    }

                    // Search/Filter utility within custom dropdown
                    if (langSearch) {
                        langSearch.addEventListener('input', function() {
                            const query = this.value.toLowerCase();
                            document.querySelectorAll('#language_dropdown_menu li.dropdown-item-text:not(.select-all-item)').forEach(item => {
                                const text = item.textContent.toLowerCase();
                                if (text.includes(query)) {
                                    item.classList.remove('d-none');
                                    item.classList.add('d-block');
                                } else {
                                    item.classList.add('d-none');
                                    item.classList.remove('d-block');
                                }
                            });
                        });

                        // Prevent Bootstrap dropdown closing when interacting with search or checkboxes
                        const dropdownMenu = document.getElementById('language_dropdown_menu');
                        if (dropdownMenu) {
                            dropdownMenu.addEventListener('click', function(e) {
                                e.stopPropagation();
                            });
                        }
                    }

                    function updateVisibilityToggles() {
                        const pcSelect = document.getElementById('physical_challenge_select');
                        const pcDiv = document.getElementById('physical_challenge_detail_div');

                        if (pcSelect && pcDiv) {
                            if (pcSelect.value === 'yes') {
                                pcDiv.classList.remove('d-none');
                                pcDiv.classList.add('d-block'); 
                            } else {
                                pcDiv.classList.add('d-none');
                                pcDiv.classList.remove('d-block');
                            }
                        }
                    }

                    const pcSelect = document.getElementById('physical_challenge_select');
                    if (pcSelect) {
                        pcSelect.addEventListener('change', updateVisibilityToggles);
                    }

                    // Global Toast Function to show errors smoothly
                    window.showToast = function(message) {
                        const toastEl = document.getElementById('validationToast');
                        const toastBody = document.getElementById('validationToastBody');
                        if (toastEl && toastBody) {
                            toastBody.innerHTML = message;

                            if (window._toastTimeout) clearTimeout(window._toastTimeout);
                            if (window._toastHideTimeout) clearTimeout(window._toastHideTimeout);

                            // Force custom animations/style
                            toastEl.style.display = 'block';
                            toastEl.offsetHeight; // Force Layout Repaint
                            toastEl.classList.add('show');
                            toastEl.style.opacity = '1';

                            window._toastTimeout = setTimeout(() => {
                                toastEl.classList.remove('show');
                                toastEl.style.opacity = '0';
                                window._toastHideTimeout = setTimeout(() => {
                                    toastEl.style.display = 'none';
                                }, 300);
                            }, 10000);
                        }
                    }

                    // Helper to track active indices in LocalStorage
                    function addActiveRowIndex(type, idx) {
                        const key = prefix + type + '_indices';
                        const savedIndices = localStorage.getItem(key);
                        let indices = savedIndices ? savedIndices.split(',').filter(x => x !== '') : [];
                        if (!indices.includes(idx.toString())) {
                            indices.push(idx.toString());
                            localStorage.setItem(key, indices.join(','));
                        }
                    }

                    // Remove dynamic row tracking from LocalStorage
                    function removeActiveRowIndex(type, idx) {
                        const key = prefix + type + '_indices';
                        const savedIndices = localStorage.getItem(key);
                        if (savedIndices) {
                            let indices = savedIndices.split(',').filter(x => x !== '');
                            indices = indices.filter(i => i !== idx.toString());
                            if (indices.length > 0) {
                                localStorage.setItem(key, indices.join(','));
                            } else {
                                localStorage.removeItem(key);
                            }
                        }

                        // Clean individual values for this index from localStorage
                        Object.keys(localStorage).forEach(k => {
                            if (k.startsWith(prefix) && k.endsWith('_' + idx)) {
                                localStorage.removeItem(k);
                            }
                        });
                    }

                    // Centralized function to add dynamic rows
                    function addDynamicRow(type, index, isUserAction = true) {
                        const templateId = type + '_row_template';
                        const containerId = type + '_lines_container';
                        const templateEl = document.getElementById(templateId);
                        const containerEl = document.getElementById(containerId);
                        if (!templateEl || !containerEl) return;

                        const template = templateEl.innerHTML;
                        const newRow = document.createElement('div');
                        newRow.innerHTML = template.replace(/name="([a-z_]+)_"/g, 'name="$1_' + index + '"');
                        const rowEl = newRow.firstElementChild;
                        containerEl.appendChild(rowEl);

                        // Bind save listeners to new inputs
                        bindInputListeners(rowEl);

                        // Override the onclick function of the close button
                        const closeBtn = rowEl.querySelector('.btn-close');
                        if (closeBtn) {
                            closeBtn.removeAttribute('onclick');
                            closeBtn.addEventListener('click', function(e) {
                                e.preventDefault();
                                window.removeRow(rowEl, type);
                            });
                        }

                        // Re-init Datepicker if it is an education or experience row
                        if (type === 'education' || type === 'experience') {
                            setTimeout(function() {
                                if (window.ahaduDatepickerInit) {
                                    window.ahaduDatepickerInit(document);
                                }
                            }, 50);
                        }

                        if (isUserAction) {
                            addActiveRowIndex(type, index);
                        }
                    }

                    window.removeRow = function(rowEl, type) {
                        // Find index of the row from the name of its first input
                        const firstInput = rowEl.querySelector('input, select, textarea');
                        let idx = null;
                        if (firstInput) {
                            const match = firstInput.name.match(/_(\d+)$/);
                            if (match) {
                                idx = match[1];
                            }
                        }

                        rowEl.remove();

                        if (idx !== null) {
                            removeActiveRowIndex(type, idx);
                        }
                    }

                    // Public Dynamic Add Functions
                    window.addBankRow = function(isUserAction = true) {
                        addDynamicRow('bank', bankCounter, isUserAction);
                        bankCounter++;
                    }

                    window.addFamilyRow = function(isUserAction = true) {
                        addDynamicRow('family', familyCounter, isUserAction);
                        familyCounter++;
                    }

                    window.addEducationRow = function(isUserAction = true) {
                        addDynamicRow('education', educationCounter, isUserAction);
                        educationCounter++;
                    }

                    window.addExperienceRow = function(isUserAction = true) {
                        addDynamicRow('experience', experienceCounter, isUserAction);
                        experienceCounter++;
                    }

                    if (form) {
                        // Bind Input Listeners function
                        function bindInputListeners(scope) {
                            const inputs = scope.querySelectorAll('input:not([type="hidden"]):not([type="file"]):not([name="birthday"]), select, textarea');
                            inputs.forEach(input => {
                                input.addEventListener('input', function() {
                                    localStorage.setItem(prefix + this.name, this.value);
                                });
                                input.addEventListener('change', function() {
                                    localStorage.setItem(prefix + this.name, this.value);
                                });
                            });
                        }

                        // Get Read-only State from python context
                        const isReadonly = ;

                        // Check if we are in edit mode
                        const editMode = form.querySelector('input[name="onboarding_id"]') !== null;

                        if (isReadonly) {
                            // Do not load local storage drafts for read-only requests
                        } else if (editMode) {
                            // Clear onboarding draft localStorage keys to prevent stale overrides
                            Object.keys(localStorage).forEach(key => {
                                if (key.startsWith(prefix) || key === 'ahadu_onboarding_language_ids') {
                                    localStorage.removeItem(key);
                                }
                            });
                        } else {
                            // --- Restore Input Values ---
                            const allInputs = form.querySelectorAll('input:not([type="hidden"]):not([type="file"]), select, textarea');
                            allInputs.forEach(input => {
                                const savedVal = localStorage.getItem(prefix + input.name);
                                if (savedVal !== null && input.name !== 'birthday') {
                                    input.value = savedVal;
                                }
                            });

                            // Restore Draft Languages Spoken Selections
                            const savedLangs = localStorage.getItem('ahadu_onboarding_language_ids');
                            if (savedLangs) {
                                const savedIds = savedLangs.split(',');
                                checkboxes.forEach(cb => {
                                    cb.checked = savedIds.includes(cb.value);
                                });
                            }
                        }

                        // --- Restore Dynamic Rows ---
                        let restoredCount = 0;
                        ['bank', 'family', 'education', 'experience'].forEach(type => {
                            const key = prefix + type + '_indices';
                            const savedIndices = localStorage.getItem(key);
                            if (savedIndices && !isReadonly) {
                                const indices = savedIndices.split(',').filter(x => x !== '');
                                indices.forEach(idx => {
                                    const indexInt = parseInt(idx);
                                    addDynamicRow(type, indexInt, false);
                                    // Make sure counter is ahead of restored index to avoid clash
                                    if (type === 'bank' && indexInt >= bankCounter) bankCounter = indexInt + 1;
                                    if (type === 'family' && indexInt >= familyCounter) familyCounter = indexInt + 1;
                                    if (type === 'education' && indexInt >= educationCounter) educationCounter = indexInt + 1;
                                    if (type === 'experience' && indexInt >= experienceCounter) experienceCounter = indexInt + 1;
                                    restoredCount++;
                                });
                            }
                        });

                        // Bind close button event listeners on existing server-rendered rows
                        document.querySelectorAll('.bank-row, .family-row, .education-row, .experience-row').forEach(rowEl => {
                            const closeBtn = rowEl.querySelector('.btn-close');
                            if (closeBtn) {
                                closeBtn.removeAttribute('onclick');
                                closeBtn.addEventListener('click', function(e) {
                                    e.preventDefault();
                                    let type = '';
                                    if (rowEl.classList.contains('bank-row')) type = 'bank';
                                    else if (rowEl.classList.contains('family-row')) type = 'family';
                                    else if (rowEl.classList.contains('education-row')) type = 'education';
                                    else if (rowEl.classList.contains('experience-row')) type = 'experience';
                                    if (type) {
                                        window.removeRow(rowEl, type);
                                    }
                                });
                            }
                        });

                        // If no server-rendered rows AND no dynamic rows restored, auto-add a default row
                        const serverBankCount = ;
                        const activeBankIndices = localStorage.getItem(prefix + 'bank_indices');
                        if (serverBankCount === 0 && !activeBankIndices && !isReadonly) {
                            window.addBankRow(true);
                        }

                        const serverFamilyCount = ;
                        const activeFamilyIndices = localStorage.getItem(prefix + 'family_indices');
                        if (serverFamilyCount === 0 && !activeFamilyIndices && !isReadonly) {
                            window.addFamilyRow(true);
                        }

                        const serverEducationCount = ;
                        const activeEducationIndices = localStorage.getItem(prefix + 'education_indices');
                        if (serverEducationCount === 0 && !activeEducationIndices && !isReadonly) {
                            window.addEducationRow(true);
                        }

                        const serverExperienceCount = ;
                        const activeExperienceIndices = localStorage.getItem(prefix + 'experience_indices');
                        if (serverExperienceCount === 0 && !activeExperienceIndices && !isReadonly) {
                            window.addExperienceRow(true);
                        }

                        // Synchronize state, apply display rules and compute labels
                        updateVisibilityToggles();
                        updateSelectedLanguages();

                        // Show alert if data was restored
                        if (restoredCount > 0 && !isReadonly) {
                            const draftAlert = document.getElementById('draft_alert');
                            if (draftAlert) {
                                draftAlert.classList.remove('d-none');
                            }
                        }

                        // Initial bind for all inputs currently on page
                        bindInputListeners(form);

                        // --- Save/Restore Active Tab ---
                        const tabLinks = document.querySelectorAll('button[data-bs-toggle="tab"]');
                        tabLinks.forEach(tab => {
                            tab.addEventListener('shown.bs.tab', function (e) {
                                localStorage.setItem(prefix + 'active_tab', e.target.id);
                            });
                        });
                        const activeTabId = localStorage.getItem(prefix + 'active_tab');
                        if (activeTabId) {
                            const tabTriggerEl = document.getElementById(activeTabId);
                            if (tabTriggerEl) {
                                tabTriggerEl.click();
                            }
                        }

                        // --- Disable All Elements if Form is Read-only ---
                        if (isReadonly) {
                            const formElements = form.querySelectorAll('input, select, textarea, button[type="submit"]');
                            formElements.forEach(el => {
                                if (el.id !== 'languageDropdown') {
                                    el.disabled = true;
                                }
                            });
                            document.querySelectorAll('.btn-close, button[onclick^="add"]').forEach(btn => {
                                btn.style.display = 'none';
                            });
                            const submitBtn = document.getElementById('btn_submit_onboarding');
                            if (submitBtn) {
                                submitBtn.style.display = 'none';
                            }
                            const langCheckboxes = document.querySelectorAll('.language-checkbox');
                            langCheckboxes.forEach(cb => {
                                cb.disabled = true;
                            });
                            const langDropdown = document.getElementById('languageDropdown');
                            if (langDropdown) {
                                langDropdown.classList.add('disabled');
                                langDropdown.disabled = true;
                            }
                        }

                        // --- Form Validation and Missing Fields Toast ---
                        const submitBtn = document.getElementById('btn_submit_onboarding');
                        if (submitBtn) {
                            form.addEventListener('submit', function(e) {
                                e.preventDefault(); 

                                const missingFieldLabels = [];
                                const invalidFields = [];
                                let firstEmptyContainerTab = null;

                                // Ensure checkboxes are synchronized first
                                updateSelectedLanguages();

                                // Enforce container row count checks
                                const bankRows = document.getElementById('bank_lines_container').querySelectorAll('.bank-row');
                                const familyRows = document.getElementById('family_lines_container').querySelectorAll('.family-row');
                                const eduRows = document.getElementById('education_lines_container').querySelectorAll('.education-row');
                                const expRows = document.getElementById('experience_lines_container').querySelectorAll('.experience-row');

                                if (bankRows.length === 0) {
                                    missingFieldLabels.push('Bank Account (Add at least one bank account)');
                                    firstEmptyContainerTab = 'bank';
                                }
                                if (familyRows.length === 0) {
                                    missingFieldLabels.push('Family Member (Add at least one family member)');
                                    if (!firstEmptyContainerTab) firstEmptyContainerTab = 'family';
                                }
                                if (eduRows.length === 0) {
                                    missingFieldLabels.push('Education Record (Add at least one education record)');
                                    if (!firstEmptyContainerTab) firstEmptyContainerTab = 'education';
                                }
                                if (expRows.length === 0) {
                                    missingFieldLabels.push('Experience Record (Add at least one experience record)');
                                    if (!firstEmptyContainerTab) firstEmptyContainerTab = 'experience';
                                }

                                // Gather standard input validation issues
                                form.querySelectorAll('input, select, textarea').forEach(el => {
                                    if (!el.checkValidity()) {
                                        let labelText = '';

                                        // 1. Try finding label element matching input ID
                                        if (el.id) {
                                            const matchingLabel = form.querySelector(`label[for="${el.id}"]`);
                                            if (matchingLabel) {
                                                labelText = matchingLabel.textContent;
                                            }
                                        }

                                        // 2. Try matching closest Bootstrap form element label
                                        if (!labelText) {
                                            const container = el.closest('.mb-3, .mb-4, [class*="col-"]');
                                            if (container) {
                                                const parentLabel = container.querySelector('label');
                                                if (parentLabel) {
                                                    labelText = parentLabel.textContent;
                                                }
                                            }
                                        }

                                        // 3. Fallback to placeholder or field name attribute
                                        if (!labelText) {
                                            labelText = el.getAttribute('placeholder') || el.getAttribute('name') || 'Required field';
                                        }

                                        // Cleanup the label name text
                                        labelText = labelText.replace(/\*/g, '').replace(/:$/, '').trim();

                                        if (labelText && !missingFieldLabels.includes(labelText)) {
                                            missingFieldLabels.push(labelText);
                                        }
                                        invalidFields.push(el);
                                    }
                                });

                                if (missingFieldLabels.length > 0) {
                                    // Switch tabs & focus on the first missing/invalid element
                                    if (invalidFields.length > 0) {
                                        const firstInvalid = invalidFields[0];
                                        const pane = firstInvalid.closest('.tab-pane');
                                        if (pane) {
                                            const tabButton = document.querySelector(`button[data-bs-target="#${pane.id}"]`);
                                            if (tabButton) {
                                                tabButton.click();
                                            }
                                        }
                                        setTimeout(() => {
                                            firstInvalid.focus();
                                            firstInvalid.scrollIntoView({ behavior: 'smooth', block: 'center' });
                                        }, 150);
                                    } else if (firstEmptyContainerTab) {
                                        const tabButton = document.querySelector(`button[data-bs-target="#${firstEmptyContainerTab}"]`);
                                        if (tabButton) {
                                            tabButton.click();
                                        }
                                    }

                                    // Display checklist in toast container
                                    let errorHtml = 'Please correct the following issues before submitting:';
                                    errorHtml += '';
                                    missingFieldLabels.forEach(lbl => {
                                        errorHtml += '
' + lbl + '';
                                    });
                                    errorHtml += '';

                                    window.showToast(errorHtml);
                                    return;
                                }

                                // Disable submit button and trigger loading indicator
                                submitBtn.disabled = true;
                                const originalBtnHtml = submitBtn.innerHTML;
                                submitBtn.innerHTML = 'Submitting...';

                                const formData = new FormData(form);

                                fetch(form.action, {
                                    method: 'POST',
                                    body: formData,
                                })
                                .then(response => {
                                    if (!response.ok) {
                                        throw new Error("Network response was not OK (HTTP " + response.status + ")");
                                    }
                                    return response.json();
                                })
                                .then(data => {
                                    if (data.success) {
                                        // On successful save, clear draft LocalStorage state completely
                                        Object.keys(localStorage).forEach(key => {
                                            if (key.startsWith(prefix) || key === 'ahadu_onboarding_language_ids') {
                                                localStorage.removeItem(key);
                                            }
                                        });
                                        // Navigate to success landing page
                                        window.location.href = data.redirect;
                                    } else {
                                        // Restore button on server-side error
                                        submitBtn.disabled = false;
                                        submitBtn.innerHTML = originalBtnHtml;

                                        // Display server validation exceptions inside toast
                                        window.showToast('Validation Error:
' + (data.error || 'Submission failed. Please check your data.') + '');
                                    }
                                })
                                .catch(error => {
                                    submitBtn.disabled = false;
                                    submitBtn.innerHTML = originalBtnHtml;
                                    console.error("AJAX Error during onboarding save:", error);

                                    // Fallback UI toast showing basic connection error
                                    window.showToast('Submission Error:
An error occurred while communicating with the server. Please try again.');
                                });
                            });
                        }
                    }
                });
